import { MarketingIdea, IdeaCategory, IdeaBudget, IdeaTimeline, IdeaRecommendation, GrowthCoverage } from '../types';

// ========================================================================
// 139 MARKETING IDEAS FRAMEWORK
// Structured marketing execution system — not a content generator.
// Categorised, filterable, executable, KPI-linked, governance-aware.
// ========================================================================

const cat = (c: IdeaCategory) => c;

function idea(
  id: number, name: string, desc: string, category: IdeaCategory,
  stage: MarketingIdea['stage'], budget: MarketingIdea['budget'],
  timeline: MarketingIdea['timeline'],
  primaryKPI: string, secondaryKPI: string,
  risk: MarketingIdea['governanceRisk'],
  assets: string[], stakeholders: string[], checklist: string[],
  outcome: string, measurement: string,
  dpiaReq = false, consentReq = false, assetConsent = false,
  retention = 'Standard retention policy applies', lawful = 'Legitimate interest'
): MarketingIdea {
  return {
    id: `idea-${id}`, name, description: desc, category, stage, budget, timeline,
    primaryKPI, secondaryKPI, governanceRisk: risk,
    requiredAssets: assets, requiredStakeholders: stakeholders,
    executionChecklist: checklist, expectedOutcome: outcome, measurementPlan: measurement,
    status: 'library', version: 1,
    dpiaRequired: dpiaReq, consentRequired: consentReq,
    assetConsentRequired: assetConsent, retentionImplication: retention, lawfulBasis: lawful,
  };
}

