// ========================================================================
// RECOMMENDATION ENGINE (Deterministic — no AI hallucination)
// ========================================================================

interface RecommendationContext {
  kpiGaps: { kpi: string; gap: number }[];
  underEngagedSegments: string[];
  activatedIdeaCategories: IdeaCategory[];
  budgetConstraint: IdeaBudget;
  timeConstraint: IdeaTimeline;
  organisationStage: MarketingIdea['stage'];
}

export function getRecommendations(
  ideas: MarketingIdea[],
  context: RecommendationContext
): IdeaRecommendation[] {
  const availableIdeas = ideas.filter(i => i.status === 'library');
  const scored: IdeaRecommendation[] = [];

  for (const idea of availableIdeas) {
    let score = 0;
    const reasons: string[] = [];
    let primaryGap = '';

    // Score based on KPI gaps
    for (const gap of context.kpiGaps) {
      const kpiLower = gap.kpi.toLowerCase();
      if (idea.primaryKPI.toLowerCase().includes(kpiLower) || idea.secondaryKPI.toLowerCase().includes(kpiLower)) {
        score += 30 + Math.min(gap.gap, 50);
        reasons.push(`Addresses ${gap.kpi} gap (${gap.gap}% below target)`);
        primaryGap = gap.kpi;
      }
    }

    // Score based on under-engaged segments
    for (const seg of context.underEngagedSegments) {
      if (idea.requiredStakeholders.some(s => s.toLowerCase().includes(seg.toLowerCase()))) {
        score += 20;
        reasons.push(`Targets under-engaged segment: ${seg}`);
      }
    }

    // Penalise over-represented categories
    const categoryCount = context.activatedIdeaCategories.filter(c => c === idea.category).length;
    if (categoryCount > 2) {
      score -= 15 * (categoryCount - 2);
      reasons.push(`Category "${idea.category}" already well-covered`);
    } else if (categoryCount === 0) {
      score += 15;
      reasons.push(`Opens new growth area: ${idea.category}`);
    }

    // Budget match
    const budgetOrder: IdeaBudget[] = ['low', 'medium', 'high'];
    const userBudgetIdx = budgetOrder.indexOf(context.budgetConstraint);
    const ideaBudgetIdx = budgetOrder.indexOf(idea.budget);
    if (ideaBudgetIdx <= userBudgetIdx) {
      score += 10;
      reasons.push('Within budget constraint');
    } else {
      score -= 20;
      reasons.push('May exceed budget constraint');
    }

    // Timeline match
    const timeOrder: IdeaTimeline[] = ['quick-win', '30-60-days', 'long-term'];
    const userTimeIdx = timeOrder.indexOf(context.timeConstraint);
    const ideaTimeIdx = timeOrder.indexOf(idea.timeline);
    if (ideaTimeIdx <= userTimeIdx) {
      score += 10;
      reasons.push('Fits timeline');
    } else {
      score -= 10;
    }

    // Stage match
    if (idea.stage === context.organisationStage) {
      score += 10;
      reasons.push(`Suitable for ${context.organisationStage} stage`);
    }

    // Low governance risk bonus
    if (idea.governanceRisk === 'low') {
      score += 5;
      reasons.push('Low governance risk');
    }

    if (score > 0) {
      scored.push({ idea, score, reasons, kpiGap: primaryGap });
    }
  }

  return scored.sort((a, b) => b.score - a.score).slice(0, 15);
}

// ========================================================================
// GROWTH COVERAGE CALCULATOR
// ========================================================================

export function calculateGrowthCoverage(ideas: MarketingIdea[]): GrowthCoverage {
  const activated = ideas.filter(i => i.status === 'activated' || i.status === 'completed');
  const categories: IdeaCategory[] = ['acquisition', 'activation', 'engagement', 'retention', 'referral', 'authority', 'community', 'partnerships'];

  const coverage: Record<string, number> = {};
  for (const cat of categories) {
    const total = ideas.filter(i => i.category === cat).length;
    const active = activated.filter(i => i.category === cat).length;
    coverage[cat] = total > 0 ? Math.round((active / total) * 100) : 0;
  }

  return coverage as unknown as GrowthCoverage;
}

export function getCategoryLabel(cat: IdeaCategory): string {
  const labels: Record<IdeaCategory, string> = {
    acquisition: 'Acquisition', activation: 'Activation', engagement: 'Engagement',
    retention: 'Retention', referral: 'Referral', authority: 'Authority',
    community: 'Community', partnerships: 'Partnerships',
  };
  return labels[cat];
}

export function getCategoryColor(cat: IdeaCategory): string {
  const colors: Record<IdeaCategory, string> = {
    acquisition: '#6366f1', activation: '#10b981', engagement: '#f59e0b',
    retention: '#ec4899', referral: '#06b6d4', authority: '#8b5cf6',
    community: '#ef4444', partnerships: '#84cc16',
  };
  return colors[cat];
}

